    93→func V30(_ context.Context, dashboard map[string]interface{}) error {
    94→	dashboard["schemaVersion"] = 30
    95→
    96→	panels, ok := dashboard["panels"].([]interface{})
    97→	if !ok {
    98→		return nil
    99→	}
   100→
   101→	for _, panel := range panels {
   102→		panelMap, ok := panel.(map[string]interface{})
   103→		if !ok {
   104→			continue
   105→		}
   106→
   107→		upgradeValueMappingsForPanel(panelMap)
   108→		migrateTooltipOptions(panelMap)
   109→
   110→		// Handle nested panels in collapsed rows
   111→		nestedPanels, hasNested := panelMap["panels"].([]interface{})
   112→		if !hasNested {
   113→			continue
   114→		}
   115→
   116→		for _, nestedPanel := range nestedPanels {
   117→			nestedPanelMap, ok := nestedPanel.(map[string]interface{})
   118→			if !ok {
   119→				continue
   120→			}
   121→			upgradeValueMappingsForPanel(nestedPanelMap)
   122→			migrateTooltipOptions(nestedPanelMap)
   123→		}
   124→	}
   125→
   126→	return nil
   127→}
   128→
   129→// upgradeValueMappingsForPanel migrates value mappings from old format to new format
   130→func upgradeValueMappingsForPanel(panel map[string]interface{}) {
   131→	fieldConfig, ok := panel["fieldConfig"].(map[string]interface{})
   132→	if !ok {
   133→		return
   134→	}
   135→
   136→	// Upgrade defaults mappings
   137→	if defaults, ok := fieldConfig["defaults"].(map[string]interface{}); ok {
   138→		if mappings, ok := defaults["mappings"].([]interface{}); ok {
   139→			var thresholds map[string]interface{}
   140→			if t, ok := defaults["thresholds"].(map[string]interface{}); ok {
   141→				thresholds = t
   142→			}
   143→			defaults["mappings"] = upgradeValueMappings(mappings, thresholds)
   144→		}
   145→	}
   146→
   147→	// Upgrade overrides mappings
   148→	overrides, hasOverrides := fieldConfig["overrides"].([]interface{})
   149→	if !hasOverrides {
   150→		return
   151→	}
   152→
   153→	for _, override := range overrides {
   154→		overrideMap, ok := override.(map[string]interface{})
   155→		if !ok {
   156→			continue
   157→		}
   158→
   159→		properties, hasProperties := overrideMap["properties"].([]interface{})
   160→		if !hasProperties {
   161→			continue
   162→		}
   163→
   164→		for _, property := range properties {
   165→			propertyMap, ok := property.(map[string]interface{})
   166→			if !ok {
   167→				continue
   168→			}
   169→
   170→			if propertyMap["id"] != "mappings" {
   171→				continue
   172→			}
   173→
   174→			mappings, ok := propertyMap["value"].([]interface{})
   175→			if !ok {
   176→				continue
   177→			}
   178→
   179→			propertyMap["value"] = upgradeValueMappings(mappings, nil)
   180→		}
   181→	}
   182→}
   183→
   184→// upgradeValueMappings converts legacy value mappings to new format
   185→func upgradeValueMappings(oldMappings []interface{}, thresholds map[string]interface{}) []interface{} {
   186→	if len(oldMappings) == 0 {
   187→		return oldMappings
   188→	}
   189→
   190→	// Check if all mappings are already in the new format
   191→	if areAllMappingsNewFormat(oldMappings) {
   192→		return oldMappings
   193→	}
   194→
   195→	valueMaps := createValueMaps()
   196→	var newMappings []interface{}
   197→	hasValueMappings := false
   198→
   199→	for _, mapping := range oldMappings {
   200→		if mappingMap, ok := mapping.(map[string]interface{}); ok {
   201→			if isNewFormatMapping(mappingMap) {
   202→				hasValueMappings = processNewFormatMapping(mappingMap, valueMaps, &newMappings, hasValueMappings)
   203→			} else {
   204→				hasValueMappings = processLegacyMapping(mappingMap, thresholds, valueMaps, &newMappings, hasValueMappings)
   205→			}
   206→		}
   207→	}
   208→
   209→	// Add consolidated value mappings at the beginning if any exist
   210→	if hasValueMappings {
